using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

var notebook = new ResearchNotebook();

var tools = new AITool[]
{
    AIFunctionFactory.Create(WebSearchTool.SearchAsync, name: "web_search",
        description: "Search the web for information. Returns titles, snippets, and URLs."),

    AIFunctionFactory.Create(notebook.SaveNote, name: "save_note",
        description: "Save a research note with a title and content for later review."),

    AIFunctionFactory.Create(notebook.GetNotes, name: "get_notes",
        description: "Retrieve all saved research notes to review findings before summarizing."),
};

IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Given a topic, you must:
        1. Break the topic into 2-3 focused sub-questions.
        2. Use web_search for each sub-question to gather information.
        3. Use save_note to record key findings from each search.
        4. Use get_notes to review all findings.
        5. Synthesize everything into a clear, cited summary.
        Be thorough but concise. Always attribute claims to sources.
        """,
    name: "ResearchAgent",
    description: "Researches topics via web search and note-taking",
    tools: tools);

Console.WriteLine("╔═══════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent            ║");
Console.WriteLine("╚═══════════════════════════════════╝");
Console.WriteLine();
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('-', 50));

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    options: new ChatClientAgentRunOptions(new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    }));

Console.WriteLine();
Console.WriteLine("Research Summary:");
Console.WriteLine(new string('=', 50));
Console.WriteLine(response.Text);
Console.WriteLine(new string('=', 50));

if (notebook.Notes.Count > 0)
{
    Console.WriteLine();
    Console.WriteLine($"{notebook.Notes.Count} research note(s) collected during this session.");
}

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------

/// <summary>
/// Simulated web search tool. Replace the body with a real search API
/// (e.g., Bing Web Search) for production use.
/// </summary>
static class WebSearchTool
{
    private static readonly HttpClient Http = new();

    public static async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        // Try a live DuckDuckGo Instant Answer API call (no key required).
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await Http.GetStringAsync(url);

            var doc = System.Text.Json.JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract (main answer)
            var abstractText = root.GetProperty("Abstract").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"[Main] {abstractText} (source: {abstractUrl})");
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var related))
            {
                foreach (var item in related.EnumerateArray().Take(5))
                {
                    var text = item.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    var link = item.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        results.Add($"- {text} ({link})");
                    }
                }
            }

            if (results.Count > 0)
            {
                return string.Join("\n", results);
            }
        }
        catch
        {
            // Fall through to fallback
        }

        return $"Search results for '{query}':\n"
             + "No detailed results available. The agent should try rephrasing the query or breaking it into simpler terms.";
    }
}

/// <summary>
/// In-memory notebook for collecting research findings.
/// </summary>
sealed class ResearchNotebook
{
    public List<(string Title, string Content, DateTime Timestamp)> Notes { get; } = [];

    public string SaveNote(
        [Description("A short descriptive title")] string title,
        [Description("The note content")] string content)
    {
        Notes.Add((title, content, DateTime.UtcNow));
        return $"Note #{Notes.Count} saved: \"{title}\"";
    }

    public string GetNotes()
    {
        if (Notes.Count == 0)
            return "No notes have been saved yet.";

        return string.Join("\n\n", Notes.Select((n, i) =>
            $"--- Note #{i + 1}: {n.Title} ---\n{n.Content}"));
    }
}

