/// <summary>
/// Simulated web search tool. Replace the body with a real search API
/// (e.g., Bing Web Search) for production use.
/// </summary>
static class WebSearchTool
{
    private static readonly HttpClient Http = new();

    public static async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        // Try a live DuckDuckGo Instant Answer API call (no key required).
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await Http.GetStringAsync(url);

            var doc = System.Text.Json.JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract (main answer)
            var abstractText = root.GetProperty("Abstract").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"[Main] {abstractText} (source: {abstractUrl})");
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var related))
            {
                foreach (var item in related.EnumerateArray().Take(5))
                {
                    var text = item.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    var link = item.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        results.Add($"- {text} ({link})");
                    }
                }
            }

            if (results.Count > 0)
            {
                return string.Join("\n", results);
            }
        }
        catch
        {
            // Fall through to fallback
        }

        return $"Search results for '{query}':\n"
             + "No detailed results available. The agent should try rephrasing the query or breaking it into simpler terms.";
    }
}

/// <summary>
