│ Require Structured Output     │ RunAsync<T>()                  │ await agent.RunAsync<MyType>(...)
│ Send Chat with System Prompt  │ ChatMessage + ChatRole.System  │ new ChatMessage(ChatRole.System, ...)
│ Cache Chat Responses          │ CachingChatClient              │ builder.UseCaching()
│ Environment Variable Support  │ ChatClientAgentOptions         │ ChatOptions property
│ Handle Tokens/Usage Info      │ UsageContent                   │ in ChatMessage.Content

=============================================================================
MOST COMMON API PATTERNS
=============================================================================

PATTERN 1: Create Basic Agent with Tools
─────────────────────────────────────────
var chatClient = new ChatClientBuilder(baseClient)
    .UseFunctionInvoking()
    .Build();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(MyService.GetWeather, "Get current weather"),
    AIFunctionFactory.Create(MyService.GetNews, "Get latest news")
};

var agent = new ChatClientAgent(
    chatClient,
    instructions: "You are a helpful assistant",
    name: "Assistant",
    tools: tools
);

var session = await agent.CreateSessionAsync();
var response = await agent.RunAsync("What's the weather?", session);


PATTERN 2: Stream Agent Response
─────────────────────────────────
await foreach (var update in agent.RunStreamingAsync(
    message: "Tell me a story...",
    session: session,
    runOptions: new ChatClientAgentRunOptions()
))
{
    if (update.Messages != null)
    {
        foreach (var msg in update.Messages)
        {
            Console.WriteLine(msg.Content);
        }
    }
}


PATTERN 3: Add Middleware to Agent
───────────────────────────────────
var agent = new ChatClientAgent(chatClient, ...)
    .AsBuilder()
    .Use(agent => new LoggingAgent(agent))
    .Use(agent => new OpenTelemetryAgent(agent))
    .Build();


PATTERN 4: Custom Tool via AIFunctionFactory
──────────────────────────────────────────────
public class Tools
{
    public static string GetWeather(string city, string units = "F")
    {
        return $"Weather in {city}: 72°{units}";
    }
}

var tool = AIFunctionFactory.Create(
    (string city) => Tools.GetWeather(city, "F"),
    name: "GetWeather",
    options: new AIFunctionFactoryOptions { Description = "Get weather for city" }
);


PATTERN 5: Structured JSON Response
────────────────────────────────────
public record SummaryResponse(string Summary, string[] KeyPoints);

var result = await agent.RunAsync<SummaryResponse>(
    message: "Summarize this document...",
    session: session,
    jsonSerializerOptions: new JsonSerializerOptions(),
    runOptions: new ChatClientAgentRunOptions()
);


PATTERN 6: Multi-Agent Collaboration (Agent as Tool)
──────────────────────────────────────────────────────
var agent2 = new ChatClientAgent(chatClient, ...);
var session2 = await agent2.CreateSessionAsync();

var agentAsFunction = agent2.AsAIFunction(session: session2);
var toolsForAgent1 = new List<AITool> { agentAsFunction };

var agent1 = new ChatClientAgent(chatClient, tools: toolsForAgent1);


PATTERN 7: Chat with Custom Options per Invocation
────────────────────────────────────────────────────
var runOptions = new ChatClientAgentRunOptions(
    new ChatOptions
    {
        Temperature = 0.7,
        MaxOutputTokens = 500,
        Tools = additionalTools,
        ToolMode = ChatToolMode.Auto
    }
);

await agent.RunAsync("Query", session, runOptions);


PATTERN 8: Load/Save Session State
───────────────────────────────────
// Save
var json = await agent.SerializeSessionAsync(session, new JsonSerializerOptions());
File.WriteAllText("session.json", json);

// Load
var sessionJson = JsonDocument.Parse(File.ReadAllText("session.json")).RootElement;
var restoredSession = await agent.DeserializeSessionAsync(sessionJson, new JsonSerializerOptions());


